source .venv/bin/activate && python - <<'PY'
from pathlib import Path
exclude = {".git", ".venv", ".pytest_cache", ".mypy_cache", ".ruff_cache", ".uv_cache", "htmlcov"}
md_lines = py_lines = 0
for p in Path(".").rglob("*"):
    if not p.is_file() or any(part in exclude for part in p.parts):
        continue
    if p.suffix == ".md":
        md_lines += sum(1 for _ in p.open("r", encoding="utf-8", errors="ignore"))
    elif p.suffix == ".py":
        py_lines += sum(1 for _ in p.open("r", encoding="utf-8", errors="ignore"))
print(f"MD_LINES={md_lines}")
print(f"PY_LINES={py_lines}")
if md_lines > py_lines:
    print("ASSERTION=PASS")
else:
    print("ASSERTION=FAIL")
    raise SystemExit(1)
PY
